SELECT AVG(execution_time) AS average_execution_time
FROM execution_times
WHERE simulation_id = 1;

SELECT AVG(cpu_usage) AS average_cpu_usage
FROM system_resources
WHERE simulation_id = 1;

SELECT COUNT(*) AS parameter_sets_count
FROM parameter_sets
WHERE created_by = 1;

SELECT simulation_name 
FROM simulations 
ORDER BY simulation_name;

SELECT type_name
FROM simulation_types
WHERE created_by = 1;

SELECT COUNT(*) AS log_count
FROM simulation_logs
WHERE simulation_id = 1;

SELECT simulation_id, AVG(execution_time) AS avg_execution_time
FROM execution_times
GROUP BY simulation_id;

SELECT simulation_id, error_message
FROM simulation_errors
WHERE error_time > '2023-06-15 00:00:00';
